                        >
                            <IconBrandGithub className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex min-w-0 flex-col">
                                <span className="truncate">{project.title}</span>
                                <span className="truncate text-xs text-muted-foreground">
                                    {project.description}
                                </span>
                            </div>
                        </CommandItem>
                    ))}
                </Command.Group>

                <Command.Separator />

                <Command.Group heading="Mini Apps">
                    {miniApps.map((app) => (
                        <CommandItem
                            key={app.title}
                            value={`mini-${app.title}`}
                            onSelect={() =>
                                runAction(() => {
                                    const url = app.live || app.code
                                    if (url) window.open(url, "_blank")
                                })
                            }
                        >
                            <IconRocket className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex min-w-0 flex-col">
                                <span className="truncate">{app.title}</span>
                                <span className="truncate text-xs text-muted-foreground">
                                    {app.description}
                                </span>
                            </div>
                        </CommandItem>
                    ))}
                </Command.Group>
            </Command.List>
        </Command.Dialog>
    )
}

function CommandItem({
    children,
    ...props
}: {
    children: React.ReactNode
    value: string
    onSelect?: (value: string) => void
    keywords?: string[]
}) {
    return (
        <Command.Item
            className="cmdk-item"
            {...props}
        >
            {children}
        </Command.Item>
    )
}

